INSERT INTO `saved_articles` (`id`, `user_id`, `news_title`, `news_url`, `news_source`, `news_description`, `news_image`, `news_published`, `type`, `created_at`, `updated_at`) VALUES
(1, 1, 'Reports: Israel Takes out Two Top Iranian Security Officials', 'https://www.breitbart.com/europe/2026/03/17/reports-israel-takes-out-two-top-iranian-security-officials/', 'Breitbart News Network', 'The Israeli military killed two top Iranian security officials in separate overnight strikes, multiple reports Tuesday indicate.', NULL, NULL, 'article', '2026-03-17 07:12:07', '2026-03-17 07:12:07'),
(2, 1, 'Browns Positioned to Benefit Via Draft-Day Trade Pitch With Chiefs', 'https://heavy.com/sports/nfl/cleveland-browns/chiefs-draft-trade-proposal-monroe-freeling/', 'Heavy.', 'The Cleveland Browns are in good position to pick up an extra draft asset from the Chiefs by trading down and still getting their top target.', NULL, NULL, 'article', '2026-03-17 07:12:16', '2026-03-17 07:12:16'),
(5, 3, 'Creating future innovators: Integrating STEAM and emerging technologies in modern education', 'https://timesofindia.indiatimes.com/education/creating-future-innovators-integrating-steam-and-emerging-technologies-in-modern-education/articleshow/129627781.cms', 'Times of India', 'Education News: The education system is rapidly evolving across the world. At the peak of the digital age, technology-driven learning models are redefining how studen.', 'https://static.toiimg.com/thumb/msid-129627826,width-1280,height-720,imgsize-67806,resizemode-6,overlay-toi_sw,pt-32,y_pad-600/photo.jpg', NULL, 'article', '2026-03-18 06:07:36', '2026-03-18 06:07:36'),
(6, 1, 'AI Summary: AI Technology', 'summary-2-1773843697', 'AI Summarizer', 'The US government recently made a decision to not allow a company called Anthropic to work with a type of powerful computer called a supercomputer. The government thought that this company was a threat to national security because it was working on artificial intelligence (AI), which is like a super smart computer that can do many things on its own.\n\nNow, the company is trying to get the government\'s decision changed in court, saying that they\'re not a threat. But the government thinks they are, and that\'s why they made the decision in the first place.\n\nAs for AI technology, it\'s getting really good at doing things like:\n\n- Playing games like chess or video games\n- Recognizing pictures and voices\n- Writing articles or stories\n- Even helping doctors make decisions\n\nBut some people are worried that AI could become too powerful and do things that we don\'t want it to do. That\'s why the government is being careful about who gets to work with supercomputers and how they use them.\n\nSome other cool things about AI technology:\n\n- It\'s getting better at understanding and speaking different languages\n- It\'s helping scientists discover new medicines and treatments\n- It\'s even helping us design new buildings and cities\n\nBut we still have to be careful and make sure that AI is used for good and not for bad.', NULL, NULL, 'summary', '2026-03-18 06:21:37', '2026-03-18 06:21:37');
